async (page) => {
  const result = await page.evaluate(() => {
    const methods = [];
    if (window.game) {
      if (window.game.input) methods.push('input: ' + Object.keys(window.game.input).join(', '));
      if (window.game.player) methods.push('player keys: ' + Object.keys(window.game.player).filter(k => typeof window.game.player[k] === 'function').slice(0,15).join(', '));
    }
    return methods.join('\n');
  });
  return result;
}

